CREATE TABLE IF NOT EXISTS installed_modules (id TEXT PRIMARY KEY, name TEXT NOT NULL, type TEXT NOT NULL, version TEXT NOT NULL, status TEXT NOT NULL, install_path TEXT NOT NULL, manifest_json JSONB NOT NULL DEFAULT '{}'::jsonb, installed_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), enabled_at TIMESTAMPTZ NULL, last_error TEXT NULL, updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS module_permissions (module_id TEXT NOT NULL, permission_type TEXT NOT NULL, permission_value TEXT NOT NULL, approved BOOLEAN NOT NULL DEFAULT FALSE, approved_at TIMESTAMPTZ NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), PRIMARY KEY (module_id, permission_type, permission_value));
CREATE TABLE IF NOT EXISTS module_kv (module_id TEXT NOT NULL, key TEXT NOT NULL, value JSONB NOT NULL DEFAULT '{}'::jsonb, updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), PRIMARY KEY (module_id, key));
